/// <summary>
/// Import data contract for <c>KJP_SM_InventCompStatementImportController</c>.
/// </summary>
[
    DataContractAttribute,
    SysOperationContractProcessingAttribute(classStr(KJP_SM_InventCompStatementImportUIBuilder))
]
public class KJP_SM_InventCompStatementImportContract
{
    System.IO.Stream            stream;
    Filename                    filename;
    str                         uploadedFileId;
    
}

Method.Source:
/// <summary>
/// Method to get and set the file input-output stream.
/// </summary>
/// <param name = "_stream">
/// Source parameter to set the file input-output stream.
/// </param>
/// <returns>
/// The file input-output stream.
/// </returns>
[Hookable(false)]
public System.IO.Stream parmStream(System.IO.Stream _stream = stream)
{
    stream = _stream;
    return stream;
}

/// <summary>
/// Method to get and set the file name.
/// </summary>
/// <param name = "_filename">
/// Source parameter to set the file name.
/// </param>
/// <returns>
/// The file name.
/// </returns>
[Hookable(false)]
public Filename parmFilename(Filename _filename = filename)
{
    filename = _filename;
    return filename;
}

/// <summary>
/// Method to get the acceptable file extensions/types.
/// </summary>
/// <returns>
/// The acceptable file extensions/types.
/// </returns>
[Hookable(false)]
public str getAllowedFileType()
{
    return KJP_CM_ConstantHelper::inventCompStatementImportFileType;
}
